function formatHits(label, hits) {
  if (!Array.isArray(hits) || hits.length === 0) {
    return `${label}: none`;
  }

  return `${label}:\n` + hits.slice(0, 8).map((hit, index) => {
    const meta = hit.metadata || {};
    const id = hit.question_id || meta.question_id || 'N/A';
    const source = hit.source_file || meta.source_file || meta.source || 'Unknown source';
    const ref = hit.evidence_reference || meta.evidence_reference || 'No evidence reference';
    const score = hit.score === null || hit.score === undefined ? 'n/a' : String(hit.score);
    const text = String(hit.text || '').replace(/\s+/g, ' ').trim();
    return [
      `${index + 1}. [${id}] ${source} | ${ref} | score=${score}`,
      text ? `   ${text}` : '   (no text returned)'
    ].join('\n');
  }).join('\n');
}

const question = String($json.question || $json.rawQuestion || '').trim();
const curatedHits = Array.isArray($json.curatedHits) ? $json.curatedHits : [];
const fallbackHits = Array.isArray($json.fallbackHits) ? $json.fallbackHits : [];

const preparedPrompt = [
  `Question:\n${question}`,
  formatHits('Curated evidence', curatedHits),
  formatHits('Fallback evidence', fallbackHits),
  'Instructions:',
  '- Answer only the question shown above.',
  '- Use ONLY facts from the evidence blocks.',
  '- Prefer curated evidence over fallback evidence.',
  '- Use fallback evidence when curated evidence is missing, partial, or not directly relevant.',
  '- If the evidence does not support a direct answer, return exactly: Not confirmed in the approved knowledge base.',
  '- For yes/no questions, use Yes. or No. only with explicit evidence.',
  '- When confirmed, include an Evidence section with 1-3 bullets using this format: - [ID] <source file> - <evidence reference>.',
  '- If only fallback evidence supports the answer, add one line before Evidence: Legacy/expanded evidence used; verify if policy has changed.'
].join('\n\n');

return [{
  json: {
    questionNumber: $json.questionNumber || 1,
    question,
    rawQuestion: $json.rawQuestion || question,
    sessionId: $json.sessionId || '',
    curatedHits,
    fallbackHits,
    preparedPrompt
  }
}];

